import React from "react";
import { Container, Sleeve, VinylRecord, VinylRecordMiddle } from "./styles";
import templeSmoke from "../../Assets/temple_smoke.png";

const RecordCover: React.FC = () => {
  return (
    <Container>
      <Sleeve src={templeSmoke}></Sleeve>
      <VinylRecord>
        <VinylRecordMiddle/>
        </VinylRecord> />
    </Container>
  );
};

export default RecordCover;
